var cells = GetInt(parameters, "cellCount", 8);
        var colorA = GetColor(parameters, "colorA", Color.FromRgb(255,255,255));
        var colorB = GetColor(parameters, "colorB", Color.FromRgb(0,0,0));
            var invert = GetBool(parameters, "invert", false);
            var aR = colorA.R / 255f;
            var aG = colorA.G / 255f;
            var aB = colorA.B / 255f;
            var bR = colorB.R / 255f;
            var bG = colorB.G / 255f;
            var bB = colorB.B / 255f;

            var size = context.TileSize;
            var buffer = new PixelBuffer(size, size);

            // Sample at pixel centers to avoid subtle asymmetric artifacts when changing
            // the number of cells. This keeps cell proportions stable across different
            // cell counts and tile sizes.
            buffer.ParallelForEachPixel((x, y) =>
            {
                var u = (x + 0.5f) / (float)size;
                var v = (y + 0.5f) / (float)size;

                var sx = u * cells;
                var sy = v * cells;
                var cx = (int)MathF.Floor(sx);
                var cy = (int)MathF.Floor(sy);

                var parity = (cx + cy) & 1;
                if (invert) parity = 1 - parity;

                float baseR = parity == 0 ? aR : bR;
                float baseG = parity == 0 ? aG : bG;
                float baseB = parity == 0 ? aB : bB;

                buffer.SetPixel(x, y, Math.Clamp(baseR, 0f, 1f), Math.Clamp(baseG, 0f, 1f), Math.Clamp(baseB, 0f, 1f), 1f);
            });

            return buffer;
}
